Bash(node -e "
const { createClient } = require\('@supabase/supabase-js'\);
require\('dotenv'\).config\({ path: '.env.local' }\);

const supabase = createClient\(
  process.env.NEXT_PUBLIC_SUPABASE_URL,
  process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY
\);

async function checkSchema\(\) {
  const tables = ['profiles', 'accounts', 'prop_accounts', 'journal_trades', 'prop_payouts', 'wallet_transactions', 'ingestion_logs', 'tv_alerts'];

  for \(const table of tables\) {
    const { data, error, status } = await supabase.from\(table\).select\('*'\).limit\(0\);
    if \(error\) {
      console.log\('❌', table, '→', error.code, error.message\);
    } else {
      console.log\('✅', table, '→ exists \(status', status + '\)'\);
    }
  }

  // Check specific columns by selecting them
  console.log\('\\n--- Column checks ---'\);

  // profiles.display_name
  const { error: e1 } = await supabase.from\('profiles'\).select\('id, display_name'\).limit\(0\);
  console.log\(e1 ? '❌ profiles\(id,display_name\): ' + e1.message : '✅ profiles\(id, display_name\)'\);

  // accounts columns
  const { error: e2 } = await supabase.from\('accounts'\).select\('id, user_id, name, kind, is_active, created_at'\).limit\(0\);
  console.log\(e2 ? '❌ accounts cols: ' + e2.message : '✅ accounts\(id, user_id, name, kind, is_active, created_at\)'\);

  // prop_accounts.user_id \(CRITICAL\)
  const { error: e3 } = await supabase.from\('prop_accounts'\).select\('id, account_id, user_id, firm_name, phase, starting_balance_usd, profit_target_percent, max_daily_loss_percent, max_overall_loss_percent'\).limit\(0\);
  console.log\(e3 ? '❌ prop_accounts cols: ' + e3.message : '✅ prop_accounts\(id, account_id, user_id, firm_name, phase, balances, targets\)'\);

  // journal_trades with net_pnl_usd
  const { error: e4 } = await supabase.from\('journal_trades'\).select\('id, user_id, account_id, symbol, category, direction, opened_at, closed_at, pnl_usd, fees_usd, net_pnl_usd, external_source, external_id, context, notes, mistakes'\).limit\(0\);
  console.log\(e4 ? '❌ journal_trades cols: ' + e4.message : '✅ journal_trades\(all expected columns\)'\);

  // prop_payouts
  const { error: e5 } = await supabase.from\('prop_payouts'\).select\('id, user_id, prop_account_id, paid_at, amount_usd, external_source, external_id'\).limit\(0\);
  console.log\(e5 ? '❌ prop_payouts cols: ' + e5.message : '✅ prop_payouts\(all expected columns\)'\);

  // wallet_transactions
  const { error: e6 } = await supabase.from\('wallet_transactions'\).select\('id, user_id, account_id, tx_type, amount_usd, notes'\).limit\(0\);
  console.log\(e6 ? '❌ wallet_transactions cols: ' + e6.message : '✅ wallet_transactions\(all expected columns\)'\);

  // ingestion_logs with meta jsonb
  const { error: e7 } = await supabase.from\('ingestion_logs'\).select\('id, user_id, status, source, items_count, duration_ms, message, meta'\).limit\(0\);
  console.log\(e7 ? '❌ ingestion_logs cols: ' + e7.message : '✅ ingestion_logs\(all expected columns\)'\);

  // tv_alerts
  const { error: e8 } = await supabase.from\('tv_alerts'\).select\('id, user_id, symbol, alert_type, timeframe, message, payload'\).limit\(0\);
  console.log\(e8 ? '❌ tv_alerts cols: ' + e8.message : '✅ tv_alerts\(all expected columns\)'\);

  // Check data counts
  console.log\('\\n--- Data counts ---'\);
  const { count: profileCount } = await supabase.from\('profiles'\).select\('*', { count: 'exact', head: true }\);
  const { count: accountCount } = await supabase.from\('accounts'\).select\('*', { count: 'exact', head: true }\);
  const { count: tradeCount } = await supabase.from\('journal_trades'\).select\('*', { count: 'exact', head: true }\);
  const { count: propCount } = await supabase.from\('prop_accounts'\).select\('*', { count: 'exact', head: true }\);
  const { count: payoutCount } = await supabase.from\('prop_payouts'\).select\('*', { count: 'exact', head: true }\);
  const { count: alertCount } = await supabase.from\('tv_alerts'\).select\('*', { count: 'exact', head: true }\);
  const { count: logCount } = await supabase.from\('ingestion_logs'\).select\('*', { count: 'exact', head: true }\);

  console.log\('profiles:', profileCount ?? 0\);
  console.log\('accounts:', accountCount ?? 0\);
  console.log\('prop_accounts:', propCount ?? 0\);
  console.log\('journal_trades:', tradeCount ?? 0\);
  console.log\('prop_payouts:', payoutCount ?? 0\);
  console.log\('tv_alerts:', alertCount ?? 0\);
  console.log\('ingestion_logs:', logCount ?? 0\);
}

checkSchema\(\).catch\(e => console.error\('FATAL:', e.message\)\);
" 2>&1)
